  Value *ZeroCmpOp;
  ICmpInst::Predicate EqPred;
  // Handle the case where X is compared with -1 and (X + 1) <= Y:
  //   (X + 1) <= Y && X != -1  -->  X < Y
  // This handles the specific case where the icmp constant is -1 (all ones).
  {
    const APInt *CmpConst;
    ICmpInst::Predicate UPred;
