        EqPred == ICmpInst::ICMP_NE && CmpConst->isAllOnes() &&
        match(UnsignedICmp,
              m_ICmp(UPred, m_Add(m_Specific(X), m_One()), m_Value(Y))) &&
        UPred == ICmpInst::ICMP_ULE)
      return Builder.CreateICmpULT(X, Y);
  }

  if (!match(ZeroICmp, m_ICmp(EqPred, m_Value(ZeroCmpOp), m_Zero())) ||
      !ICmpInst::isEquality(EqPred))
    return nullptr;
