/// Handle (X + 1) <= Y && X != -1 --> X < Y
/// This is a special case of unsigned underflow check where the icmp
/// compares against -1 (all ones) instead of 0.
static Value *foldAddOneAndICmpMinusOne(ICmpInst *Cmp0, ICmpInst *Cmp1,
                                        bool IsAnd,
                                        InstCombiner::BuilderTy &Builder) {
  // Match the pattern: (X + 1) <= Y && X != -1
  Value *X, *Y;
  ICmpInst::Predicate Pred0, Pred1;
  const APInt *C;
  if (!IsAnd)
    return nullptr;
  // Match: X != -1 (where -1 is all ones)
  if (!match(Cmp0, m_ICmp(Pred0, m_Value(X), m_APInt(C))) ||
      Pred0 != ICmpInst::ICMP_NE || !C->isAllOnes())
    return nullptr;
  // Match: (X + 1) <= Y
  if (!match(Cmp1, m_ICmp(Pred1, m_Add(m_Specific(X), m_One()), m_Value(Y))) ||
      Pred1 != ICmpInst::ICMP_ULE)
    return nullptr;
  return Builder.CreateICmpULT(X, Y);
}

/// Commuted variants are assumed to be handled by calling this function again
/// with the parameters swapped.
static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
